def prove_pm4_71(sys: System) -> Proof:
    """Implication in terms of biconditional and conjunction.  Theorem *4.71 of
    [WhiteheadRussell] p. 120.  (Contributed by NM, 21-Jun-1993.)  (Proof
    shortened by Wolf Lammen, 2-Dec-2012.)
    """
    lb = ProofBuilder(sys, "pm4.71")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ) → φ )", ref="simpl", note="simpl")
    s2 = lb.ref("s2", "( ( φ → ( φ ∧ ψ ) ) ↔ ( ( φ → ( φ ∧ ψ ) ) ∧ ( ( φ ∧ ψ ) → φ ) ) )", s1, ref="biantru", note="biantru")
    s3 = lb.ref("s3", "( ( φ → ψ ) ↔ ( φ → ( φ ∧ ψ ) ) )", ref="anclb", note="anclb")
    s4 = lb.ref("s4", "( ( φ ↔ ( φ ∧ ψ ) ) ↔ ( ( φ → ( φ ∧ ψ ) ) ∧ ( ( φ ∧ ψ ) → φ ) ) )", ref="dfbi2", note="dfbi2")
    res = lb.ref("res", "( ( φ → ψ ) ↔ ( φ ↔ ( φ ∧ ψ ) ) )", s2, s3, s4, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

